function ModelGuild:OnGuildListResp(pb)
    --公会列表请求返回
    local showAll = pb.showAll       --是否展示所有 true 展示所有公会，false展示不满人的公会
    local guildName = pb.guildName    --标注是否使用名字搜索
    self._punishTime = pb.punishTime or "0"
    self._applyList = {}              --已请求公会列表
    self._reqGuildList = {}           --公会信息列表

    
    for k,v in ipairs(pb.infos or {}) do
        local info = StructGuildInfo:New()
        info:CreateByPb(v, true)
        table.insert(self._reqGuildList, info)
    end

    for k,v in ipairs(pb.applyList or {}) do
        self._applyList[v] = v
    end


end

function ModelGuild:OnGuildMemberListResp(pb)
    --公会成员列表请求返回
    local infos = pb.infos                          --成员信息列表
    local guildId = pb.guildId                      --公会Id
    local guildName = pb.guildName                  --公会名称
    local guildNotice = pb.guildNotice              --公会宣言
    local level = pb.level                          --公会等级
    local activityWeek = pb.activityWeek            --公会周活跃度
    local levelLimit = pb.levelLimit                --公会招募等级条件
    local serverId = pb.serverId                    --服务器ID
    local power = 0
    local flagId = pb.flagId
    local flagBgId = pb.flagBgId
    local noticeKey = pb.noticeKey or ""

    if noticeKey ~= "" then
        guildNotice = ccLngText(noticeKey)
    else
        guildNotice = LWordMaskUtil.ClearShieldWord(guildNotice)
    end

    local _guildMemberList = {}
    for i, v in ipairs(infos) do
        local info = StructGuildMemberInfo:New()
        info:CreateByPb(v)
        table.insert(_guildMemberList, info)
        power = power + info.info._power
    end
    table.sort(_guildMemberList, function(a, b)
        if a.position ~= b.position then
            return a.position < b.position
        end
        if a.info._playerState ~= b.info._playerState then
            return a.info._playerState > b.info._playerState
        end
        if a.info._power ~= b.info._power then
            return a.info._power > b.info._power
        end
        return a.info._playerId < b.info._playerId
    end)
    local _selfGuildInfo = self:GetGuildInfo()
    if _selfGuildInfo and _selfGuildInfo.guildId == guildId and serverId == 0 then
        self._guildMemberList = _guildMemberList
        self._guildInfo.count = #infos
    else
        local chairman = nil
        for i, v in ipairs(_guildMemberList) do
            if v.position == 1 then
                chairman = v.info
                break
            end
        end
        local guildInfo = {
            guildId = guildId,
            guildName = guildName,
            guildNotice = guildNotice,
            level = level,
            activityWeek = activityWeek,
            chairman = chairman,
            levelLimit = levelLimit,
            count = #_guildMemberList,
            serverId = serverId,
            power = power,
            flagId = flagId,
            flagBgId = flagBgId,
        }
        GF.OpenWndBottom("UIGdInfoPop", { guildInfo = guildInfo, guildMemberList = _guildMemberList })
        FireEvent(EventNames.ON_GUILD_MELEE_RESULT, false)
    end
    FireEvent("OnGuildMemberListResp")

end

function ModelGuild:OnGuildInfoResp(pb)
    --公会信息请求返回
    local isNew = pb.isNew                --是否新的公会通知
    self._receiveActivityLevel = {}       --已领取的活跃度等级记录
    self._guildInfo = StructGuildInfo:New()     --公会信息
    self._guildInfo:CreateByPb(pb.info)
    self._selfGuildInfo = StructGuildMemberInfo:New()       --自身信息
    self._selfGuildInfo:CreateByPb(pb.selfInfo)
    
    for k,v in ipairs(pb.receiveActivityLevel or {}) do
        local id = v
        self._receiveActivityLevel[id] = id
    end 
    
    if (isNew == 1) then
        gModelPlayer:SetGuildId(self._guildInfo.guildId)
        gModelPlayer:SetGuildName(self._guildInfo.guildName)
        GF.ShowMessage(string.replace(ccClientText(12506), self._guildInfo.guildName))
        GF.CloseWndByName("UIGdInfoPop")
        gModelGuildMelee:OnGuildMeleeStateReq()
        FireEvent(EventNames.ON_JOIN_GUILD)
    end

    FireEvent("OnGuildInfoResp")
end

function ModelGuild:OnGuildApplyInfoResp(pb)
    --公会信息请求返回
    self._applyPlayerInfoList = {}           --申请的玩家信息列表
    for i = 1, #pb.playerIds do
        local playerInfo = StructPlayerInfo:New()
        playerInfo:CreateByPb(pb.playerIds[i])
        playerInfo.applyTime = pb.applyTime[i]        --申请的玩家申请时间
        table.insert(self._applyPlayerInfoList, playerInfo)
    end
end

