function ModelGuild:OnJoinGuildResp(pb)
    --加入公会请求返回
    GF.ShowMessage(ccClientText(12502))
    local type = pb.type                  --加入公会请求类型 1.单个申请，2一键加入
    if (type == 2) then
        return
    end
    local guildId = pb.guildId            --公会Id（单个申请使用）
    if (guildId) then
        local list = self._applyList or {}
        list[guildId] = guildId
        self._applyList = list
    end
end

