function ModelGuild:OnGuildInfoChangeResp(pb)
    --公会信息修改请求返回
    local type = pb.type                  --修改类型 : 1.公会名称 2.公会宣言 3.公会公告，4公会招募条件
    local content = pb.content            --修改内容
    local levelLimit = pb.levelLimit      --等级要求（招募条件使用）
    local approve = pb.approve            --是否需要审批（招募条件使用）
    local push = pb.push                  --是否需要发布
    local renameTime = pb.renameTime
    local pushState = pb.pushState
    if (content and content ~= "") then
        if (ccLngText(content) and ccLngText(content) ~= "") then
            content = ccLngText(content)
        end
        content = LWordMaskUtil.ClearShieldWord(content)
    end
    if (type == 1) then
        if (renameTime ~= nil and renameTime ~= 0 and renameTime ~= "") then
            local time = GetTimestamp()
            local timespan = tonumber(renameTime) / 1000 - time
            GF.ShowMessage(string.replace(ccClientText(12560), LUtil.FormatTimeToMin(timespan)))
            return
        end
        self._guildInfo.guildName = content
        GF.ShowMessage(ccClientText(12549))
    elseif (type == 2) then
        self._guildInfo.notice = content
        GF.ShowMessage(ccClientText(12550))
    elseif (type == 3) then
        self._guildInfo.announcement = content
        GF.ShowMessage(ccClientText(12509))
    elseif (type == 4) then
        self._guildInfo.levelLimit = levelLimit
        self._guildInfo.approve = approve
        if (push == 1) then
            self._guildInfo.recruitCount = self._guildInfo.recruitCount + 1
            if (pushState == 0) then
                GF.ShowMessage(ccClientText(12491))
                GF.CloseWndByName("UIGdRecruitTips")
            end
        else
            GF.ShowMessage(ccClientText(12563))
        end
    end
end

