function ModelGuild:OnGuildChangeResp(pb)
    --公会信息变动通知
    local type = pb.type                          --变动类型 ：1公会公告 ，2加入公会，3离开公会(主动或被动)，4.权限变动,
    --5.有新的入会申请 6公会宣言 7公会招募条件变动 8公会名称变动 9公会捐献,
    --10招募发布，11公会解散
    local playerName = pb.playerName          --变动人员名称
    local position = pb.position              --变动后权限
    local oldPosition = pb.oldPosition        --变动前权限
    local processName = pb.processName        --操作人
    if (type == 2) then
        GF.ShowMessage(string.replace(ccClientText(12546), playerName))
        if not self._guildInfo then
            return
        end
        self:OnGuildInfoReq()
        return
    elseif type == 11 then
        gModelGuildMelee:ClearMeleeSignUpInfo()
        GF.ShowMessage(ccClientText(12580))
        self:OnLeaveGuild()
        return
    elseif (type == 3) then
        gModelGuildMelee:ClearMeleeSignUpInfo()
        if playerName then
            GF.ShowMessage(string.replace(ccClientText(12548), playerName))
        end
        if ((playerName and playerName == gModelPlayer:GetPlayerName()) or playerName == "") then
            --自己退出公会
            self:OnLeaveGuild()
        else
            self:OnGuildInfoReq()
        end
        return
    elseif (type == 4) then
        self:OnGuildInfoReq()
    end
    if not self._guildInfo then
        self:OnGuildInfoReq()
        return
    end
    if playerName ~= gModelPlayer:GetPlayerName() then
        self:OnGuildInfoReq()
    end
end

function ModelGuild:OnGuildDailyBoxInfoResp(pb)
    --公会每日经验宝箱信息请求返回
    local exp = pb.exp                                              --公会每日经验
    local integral = pb.integral                                    --玩家单日累积捐献积分
    local receiveIds = pb.receiveIds                                --已领取宝箱Id集合
    local donateInfoList = pb.donateInfoList                        --捐献数据集合
    local remainDonateExpCount = pb.remainDonateExpCount            --公会每日剩余可通过捐献获得经验人数
    local weekIntegral = pb.weekIntegral                            --玩家周累积捐献积分

    self._exp = exp
    self._integral = integral
    self._weekIntegral = weekIntegral
    local _receiveIds = {}
    for i, v in ipairs(receiveIds) do
        _receiveIds[v] = v
    end
    self._receiveIds = _receiveIds
    local _donateInfoList = {}
    for i, v in ipairs(donateInfoList) do
        local donateRefId = v.donateRefId                           --捐献表refId
        local donateCount = v.donateCount                           --玩家当天本种捐献已捐献次数
        _donateInfoList[donateRefId] = donateCount
    end
    self._donateInfoList = _donateInfoList
    self._remainDonateExpCount = remainDonateExpCount
end

