function ModelGuild:OnGuildSkillInfoResp(pb)
    --公会技能信息获取返回
    local _skillInfo = self:GetGuildSkillInfo()
    if (not _skillInfo) then
        _skillInfo = {}
    end
    local info = StructGuildSkillInfo:New()
    info:CreateByPb(pb.info)
    local _oldSkillInfo = _skillInfo[info.type]
    if (_oldSkillInfo and #info.skillId > 0) then
        local list = {}
        for i, v in ipairs(_oldSkillInfo.skillId) do
            list[v] = v
        end
        if (#info.skillId > #_oldSkillInfo.skillId) then
            for i, v in ipairs(info.skillId) do
                if (not list[v]) then
                    GF.OpenWnd("UIJNUpPop", { newSkill = v })
                    break
                end
            end
        else
            local newList = {}
            local oldSkill, newSkill
            for i, v in ipairs(info.skillId) do
                newList[v] = v
                if (not list[v]) then
                    newSkill = v
                end
            end
            for i, v in ipairs(_oldSkillInfo.skillId) do
                if (not newList[v]) then
                    oldSkill = v
                end
            end
            if (oldSkill and newSkill) then
                GF.OpenWnd("UIJNUpPop", { oldSkill = oldSkill, newSkill = newSkill })
            end
        end
    end
