function ModelGuild:OnGuildDailyAttributeResp(pb)
    --公会每日信息请求返回
    if not self._guildInfo then
        self._guildInfo = {}
    end
    if (pb.exp) then
        self._guildInfo.exp = pb.exp                                              --公会每日经验
    end
    if (pb.receiveActivityLevel) then
        self._receiveActivityLevel = {}                                           --已领取的活跃度等级记录
        for i = 1, #pb.receiveActivityLevel do
            local id = pb.receiveActivityLevel[i]
            self._receiveActivityLevel[id] = id
        end
    end

    if not self._selfGuildInfo then
        return
    end

    if (pb.activityLevel) then
        self._selfGuildInfo.activityLevel = pb.activityLevel                        --玩家活跃度等级
    end
    if (pb.activityHistory) then
        self._selfGuildInfo.activityHistory = pb.activityHistory                    --玩家历史活跃度
    end
    if (pb.activity) then
        self._selfGuildInfo.activity = pb.activity                                   --玩家当日活跃度
    end
    if (pb.activityWeek) then
        self._selfGuildInfo.activityWeek = pb.activityWeek                          --玩家周活跃度
    end
    if (pb.activityGuild) then
        self._selfGuildInfo.activityGuild = pb.activityGuild                         --玩家公会总活跃度
    end
    if (pb.donate) then
        self._selfGuildInfo.donate = pb.donate                                      --今日捐献类型 0,未捐华献，1金币捐献，2钻石捐献，3豪捐献
    end
    if (pb.guildActivity) then
        self._guildInfo.activity = pb.guildActivity                                   --公会活跃度
    end
    if (pb.guildExp) then
        self._guildInfo.exp = pb.guildExp                                             --公会经验
    end
    if (pb.guildLevel) then
        self._guildInfo.level = pb.guildLevel                                         --公会等级
    end
end

