function ModelGuild:OnGuildBraveLogResp(pb)
    --公会副本通关日志请求返回
    local logList = {}                                --日志列表
    for i = 1, #pb.logList do
        local log = pb.logList[i]
        local info = StructGuildBraveLog:New()
        info:CreateByPb(log, true)
        table.insert(logList, info)
    end
    self._logList = logList
end

function ModelGuild:OnGuildBraveHurtRankResp(pb)
    --公会副本伤害排行榜请求返回
    local logList = {}                                --伤害排行信息
    local _selfRank = pb.selfRank             --自己的排行信息
    for i = 1, #pb.logList do
        local log = pb.logList[i]
        local info = StructRankInfo:New()
        info:CreateByPb(log, true)
        table.insert(logList, info)
    end
    local selfRank = StructRankInfo:New()
    selfRank:CreateByPb(_selfRank, true)
    local ref = gModelRank:GetRankingRefData(ModelRank.RANK_GUILDBBRAVE)
    local quantity = ref.quantity
    if (selfRank.rank > quantity) then
        selfRank.rank = 0
    end
    if (not selfRank.info) then
        selfRank.info = {
            _playerId = gModelPlayer:GetPlayerId(),
            _name = gModelPlayer:GetPlayerName(),
            _head = gModelPlayer:GetPlayerHead(),
            _headFrame = gModelPlayer:GetPlayerHeadFrame(),
            _grade = gModelPlayer:GetPlayerLv()
        }
    end
    self._rankData = {
        selfRank = selfRank,
        oherRank = logList,
    }
end

