function ModelGuild:OnGuildListReq(showAll, guildName)
    --公会列表请求
    local pb = LProtoHelper.CreateProto(LProtoIds.GuildListReq)
    pb.showAll = 1      --是否展示所有 1 展示所有公会，0展示不满人的公会
    if (guildName) then
        if (self._bSearchCd == true) then
            --GF.ShowMessage(string.replace(ccClientText(12494),self._seekTime))
            GF.ShowMessage(ccClientText(12545))
            return
        end
        self._bSearchCd = true
        pb.guildName = guildName  --字段不为空时，使用名字搜索
        self._seekTime = self:GetGuildConfigRefByKey("searchCd")
        self._timer:TimerCreate("SearchCd", function(...)
            self:OnNextDayZero(...)
        end, 1, true, 1)
    end
    SendMessage(pb, LProtoIds.GuildListReq)
end

function ModelGuild:OnNextDayZero(key)
    --冷却计时
    self._timer:TimerRemoveByKey(key)
    local time = 0
    if (key == "SearchCd") then
        self._seekTime = self._seekTime - 1
        time = self._seekTime
        if (time <= 0) then
            self._bSearchCd = false
        end
    end
    if (time > 0) then
        self._timer:TimerCreate(key, function(...)
            self:OnNextDayZero(...)
        end, 1, true, 1)
    end
end

