function ModelGuild:OnGuildDonateRankResp(pb)
    local rankList = pb.rankList
    local selfRank = pb.selfRank

    local _rankList = {}
    for i, v in ipairs(rankList) do
        local info = StructRankInfo:New()
        info:CreateByPb(v)
        table.insert(_rankList, info)
    end
    local _selfRank = StructRankInfo:New()
    _selfRank:CreateByPb(selfRank)

    local ref = gModelRank:GetRankingRefData(ModelRank.RANK_GUILD_DONATE)
    local quantity = ref.quantity
    if _selfRank.rank > quantity then
        _selfRank.rank = 0
    end
    if not _selfRank.info then
        _selfRank.info = {
            _playerId = gModelPlayer:GetPlayerId(),
            _name = gModelPlayer:GetPlayerName(),
            _head = gModelPlayer:GetPlayerHead(),
            _headFrame = gModelPlayer:GetPlayerHeadFrame(),
            _grade = gModelPlayer:GetPlayerLv()
        }
    end
    self._rankDonateData = {
        selfRank = _selfRank,
        oherRank = _rankList,
    }
end

