function ModelGuild:GetReqGuildList(bool, languageRefId)
    --获取请求返回的公会列表
    local list = {}
    local _reqGuildList = self._reqGuildList
    if not _reqGuildList then
        return {}
    end
    for i, v in ipairs(_reqGuildList) do
        if not languageRefId or languageRefId == ModelGuild.TYPE_LANGUAGE_ALL or v.languageRefId == languageRefId then
            local count = self:GetGuildNumByLv(v.level)
            v.isManchu = v.count >= count and 1 or 0
            if (bool == 1) then
                --不显示满人
                if (v.count < count) then
                    table.insert(list, v)
                end
            else
                table.insert(list, v)
            end
        end
    end
    table.sort(list, function(a, b)
        if a.isManchu ~= b.isManchu then
            return a.isManchu < b.isManchu
        end
        if (a.level ~= b.level) then
            return a.level > b.level
        end
        if a.count ~= b.count then
            return a.count > b.count
        end
        if a.power ~= b.power then
            return a.power > b.power
        end
        return a.guildId < b.guildId
    end)
    return list
end

