function ModelGuild:GetGuildLogByType(type)
    local list = self._guildLogList[type]
    local logList = {}
    if not list then
        return {}
    end
    for i = 1, #list do
        local logdata = list[i]
        local time = logdata.time
        --local Y = LUtil.OSDate("%Y", time/1000)
        local m = LUtil.OSDate("%m", time / 1000)
        local d = LUtil.OSDate("%d", time / 1000)
        local key = string.replace(ccClientText(12586), m, d)
        if (#logList > 0) then
            local bool = false
            for j = 1, #logList do
                local log = logList[j]
                if (logList[j].time == key) then
                    table.insert(log.list, logdata)
                    bool = true
                end
            end
            if (not bool) then
                local log = {}
                log.time = key
                log.sort = tonumber(m) * 30 + tonumber(d)
                log.list = {}
                log.timestamp = time
                table.insert(log.list, logdata)
                table.insert(logList, log)
            end
        else
            local log = {}
            log.time = key
            log.timestamp = time
            log.sort = tonumber(m) * 30 + tonumber(d)
            log.list = {}
            table.insert(log.list, logdata)
            table.insert(logList, log)
        end
    end
    table.sort(logList, function(a, b)
        return a.timestamp > b.timestamp
    end)
    for i, v in ipairs(logList) do
        table.sort(v.list, function(a, b)
            return a.time > b.time
        end)
    end
    return logList
end

function ModelGuild:GetGuildLogDesByLog(log)
    local LogTypeRef = self:GetGuildLogTypeRefByRefId(log.type)
    local name = "[" .. ccLngText(LogTypeRef.typeName) .. "] "
    local time = LUtil.OSDate("%H:%M  ", log.time / 1000)
    local ref = self:GetGuildLogRefByRefId(log.refId)
    local str = ccLngText(ref.content)

    local paraType = ref.paraType
    local paraKeys = {}
    if not string.isempty(paraType) then
        local parasArr = string.split(paraType, "|")
        for i, v in ipairs(parasArr) do
            local arr = string.split(v, "=")
            local index = tonumber(arr[1])
            local type = tonumber(arr[2])
            paraKeys[index] = type
        end
    end

    local logList = {}
    for i, v in ipairs(log.params) do
        local value = v
        local paraType = paraKeys[i] or 0
        if log.refId == 14 and i == 3 then
            ---奖励串处理
            local temp = string.sub(v, 4)
            value = gModelItem:FormatItemListStr(temp)
        elseif paraType == 1 then
            value = ccLngText(value)
        elseif paraType == 2 then
            value = LUtil.NumberCoversion(value)
        elseif paraType == 3 then
            value = gModelItem:FormatItemListStr(value)


        end
        table.insert(logList, value)
    end

    local result
    if log.refId == 23 then
        result= string.replace(str,log.params[2])
    else
        result = LStringUtil.ReplaceStringCommon(str, nil, unpack(logList))

    end

 
    local des = {
        name = name,
        time = time,
        str = result,
    }
    return des
end

function ModelGuild:GetAddGuildByTime()
    --是否可加入公会
    local time = GetTimestamp()
    local _punishTime = self._punishTime or "0"
    local punishTime = tonumber(_punishTime) / 1000
    if (time > punishTime) then
        return true
    end
    GF.ShowMessage(string.replace(ccClientText(13117), LUtil.FormatTimeToMin(punishTime - time)))
    return false
end

function ModelGuild:GetAssignCDRByTime()
    --是否可转让会长
    local time = GetTimestamp()
    local createTime = tonumber(self._guildInfo.createTime) / 1000
    local presidentTime = self:GetGuildConfigRefByKey("presidentHandoverTime")
    if ((time - createTime) / 3600 > presidentTime) then
        return true
    end
    GF.ShowMessage(string.replace(ccClientText(13118), presidentTime, LUtil.FormatTimeToMin(createTime + presidentTime * 3600 - time)))
    return false
end

