function ModelGuild:GetGuildSkillRedByType(type)
    if (not self:GetBHaveGuild()) then
        return false
    end
    if (not gModelFunctionOpen:CheckIsOpened(12101000, false)) then
        return false
    end
    local _skillInfolist = self:GetGuildSkillInfo()
    local refId = (_skillInfolist[type] and _skillInfolist[type].attributeId)
    if (refId and refId > 0) then
        local ref = self:GetGuildSkillAttrRefByRefId(refId)
        refId = ref.nextId
    else
        refId = self:GetGuildSkillInitial(type)
    end
    local ref = self:GetGuildSkillAttrRefByRefId(refId)
    if (not ref or not ref.nextId or ref.nextId == 0) then
        return false
    end
    for i, v in pairs(_skillInfolist) do
        if (i ~= type) then
            local id = v.attributeId
            local skillAttr = self:GetGuildSkillAttrRefByRefId(id)
            if (ref.otherLevel > 0 and (not skillAttr or skillAttr.level < ref.otherLevel)) then
                return false
            end
        end
    end
    local items = LxDataHelper.ParseItem_3List(ref.upNeed)
    return gModelItem:IsUpNeedEnough(items)
end

