function ModelGuild:GetBargainItemInfo()
    local itemList, dialoguePrice, dialogueItem = {}, 0, 0
    local bargainItems = gModelGuild:GetBargainItems()
    for i = 1, #bargainItems.refIds do
        local id = bargainItems.refIds[i]
        local cfg = GameTable.ClanBargainShopRef[id]
        if cfg then
            table.insert(itemList, LxDataHelper.ParseItem_4(cfg.reward))

            local dialogueInfo = string.split(cfg.price, "=")
            dialogueItem = tonumber(dialogueInfo[2])
            dialoguePrice = dialoguePrice + tonumber(dialogueInfo[3])
        end
    end
    return itemList, dialoguePrice, dialogueItem, bargainItems.bargainPrice
end

