function ModelGuild:GetSignOutGuildCd()
    --退出联盟惩罚：惩罚时长，单位小时
    local cd = self:GetGuildConfigRefByKey("specialSignOutGuildCd")
    local cdArr = string.split(cd, ",")
    local dayPast = gLGameLogin:GetServerOpenDay()
    local isNewDay = dayPast >= tonumber(cdArr[1]) --gLGameLogin:IsExceedOpenTime(tonumber(cdArr[1]))
    if (isNewDay) then
        return isNewDay, self:GetGuildConfigRefByKey("signOutGuildCd")
    else
        return isNewDay, tonumber(cdArr[2])
    end
end

