function ModelGuild:GetRandomManifesto(type)
    --随机公会宣言
    local refIdList = {}
    for i, v in pairs(GameTable.ClanAnnouncementRef) do
        if (type == v.type) then
            table.insert(refIdList, v.refId)
        end
    end
    local index = math.random(1, #refIdList)
    if (not index) then
        return ""
    end
