function ModelGuild:GetGuildSkillInitialAttr(type)
    local list = {}
    local key = "guildSkillInitialattr" .. type
    local value = GameTable.ClanSkillConfigRef[key]
    local valueList = LUtil.GetRefAttrData(value)
    for i, v in ipairs(valueList) do
        list[v.refId] = v
    end
    return list
end

function ModelGuild:GetGuildSkillAttrRefAttrByRefId(type, refId)
    --根据当前属性id获取总属性
    local list = {}
    local attrList = self:GetGuildSkillInitialAttr(type)

    if (refId == 0) then
        for i, v in pairs(attrList) do
            table.insert(list, v)
        end
        return list
    end
    local ref = GameTable.ClanSkillAttrRef[refId]
    local job = ref.Job
    local level = ref.level
    --LUtil.GetRefAttr(attrStr)
    for i, v in pairs(GameTable.ClanSkillAttrRef) do
        if (v.Job == job and v.level <= level) then
            local attr = LUtil.GetRefAttr(v.attr)
            local attrData = attrList[attr.refId]
            if (attrData) then
                attrData.value = attrData.value + attr.value
            else
                attrData = attr
            end
            attrList[attr.refId] = attrData
        end
    end
    for i, v in pairs(attrList) do
        table.insert(list, v)
    end
    if (#list > 1) then
        table.sort(list, function(a, b)
            if (a.refId ~= b.refId) then
                return a.refId < b.refId
            end
            return false
        end)
    end
    return list
end

function ModelGuild:GetGuildSkillAttrRefNeedByRefId(refId)
    --根据当前属性id获取总消耗
    local list = {}
    local needList = {}
    if (refId == 0) then
        return {}
    end
    local ref = GameTable.ClanSkillAttrRef[refId]
    local job = ref.Job
    local level = ref.level
    for i, v in pairs(GameTable.ClanSkillAttrRef) do
        if (v.Job == job and v.level <= level) then
            local itemList = LxDataHelper.ParseItem_3List(v.upNeed)
            for i, v in pairs(itemList) do
                local itemData = needList[v.itemId]
                if (itemData) then
                    itemData.itemNum = itemData.itemNum + v.itemNum
                else
                    itemData = v
                end
                needList[itemData.itemId] = itemData
            end
        end
    end
    for i, v in pairs(needList) do
        table.insert(list, v)
    end
    return list
end

function ModelGuild:GetGuildSkillAttrRefPosByRefId(refId)
    --根据当前属性id获取下一级属性位置
    local pos = -1
    if (refId == 0) then
        return 1
    end
    local ref = GameTable.ClanSkillAttrRef[refId]
    local job = ref.Job
    local level = ref.level
    for i, v in pairs(GameTable.ClanSkillAttrRef) do
        if (v.Job == job and v.level == level + 1) then
            pos = v.pos
            break
        end
    end
    return pos
end
function ModelGuild:GetGuildSkillRefNexdArrtByRefId(type, refId)
    --根据type获取公会技能下级属性
    local str = ""
    local nexRefId = 0
    if (not refId or refId == 0) then
        nexRefId = self:GetGuildSkillInitial(type)
    else
        local ref = GameTable.ClanSkillAttrRef[refId]
        nexRefId = ref.nextId
    end
    local ref = GameTable.ClanSkillAttrRef[nexRefId]
    if (ref and ref.attr) then
        local attr = LUtil.GetRefAttr(ref.attr)
        local name = gModelHero:GetAttributeNameById(attr.refId)
        local value = gModelHero:GetAttributeValueNoNameByIdAndVal(attr.refId, attr.numType, attr.value)
        str = string.replace(ccClientText(12587), name, value)
    end
    return str
end
function ModelGuild:GetGuildSkillRefUpNeedByRefId(type, refId)
