    if (refId == 0) then
        nexRefId = self:GetGuildSkillInitial(type)
    else
        local ref = GameTable.ClanSkillAttrRef[refId]
        nexRefId = ref.nextId
    end
    local ref = GameTable.ClanSkillAttrRef[nexRefId]
    if (ref and ref.upNeed and ref.upNeed ~= "") then
        local itemList = LxDataHelper.ParseItem_3List(ref.upNeed)
        list = itemList
    end
    return list
end

