function ModelGuild:GetGuildBuyNumNeed(num)
    --公会副本挑战次数购买需求----第一次需求|第二次需要|第三次需要|第四次需要…
    num = num and self._guildBrave.battleBuyCount + num or self._guildBrave.battleBuyCount + 1
    local needStr = GameTable.ClanDungeonConfigRef["GuildBuyNumNeed"]
    local attrArry = string.split(needStr, "|")
    if (num > #attrArry) then
        num = #attrArry
    end
    local itemStr = attrArry[num]
    local item = LxDataHelper.ParseItem_3(itemStr)
    return item
end

function ModelGuild:GetGuildDungeonEncourageRefByRefId(refId)
