    return ref     --nil 满级
end

function ModelGuild:GetGuildDungeonMonsterRefAwardByRefId(refId, type)
    --获取奖励详情
    local list = {}
    local ref = GameTable.GuildDungeonMonsterRef[refId]
    if not ref then
        return list
    end
    if (type == 1) then
        list = LxDataHelper.ParseItem_3List(ref.challengeReward)
    elseif (type == 2) then
        list = LxDataHelper.ParseItem_3List(ref.killRewardPersonal)
        local personallist = LxDataHelper.ParseItem_3List(ref.killRewardGuild)
        for i, v in ipairs(personallist) do
            table.insert(list, v)
        end
    else
        list = LxDataHelper.ParseItem_3List(ref.lastKillReward)
    end
    return list
end

