function ModelGuild:SetGuyNumPop(type)--设置购买弹窗		1-挑战，2-【+】，3-扫荡
    local _braveInfo = self:GetGuildBraveInfo()
    local battleBuyCount=_braveInfo.battleBuyCount
    local guyNum=self:GetVipBraveAddNum(2)
