        if(num < item.itemNum)then
            gModelGeneral:OpenGetWayWnd({itemId = itemId})
            return
        end
        --购买协议
        gModelGuildBoss:OnGuildBuyReq(type)
    end, consume={itemNum,itemId} })
end--]]

function ModelGuild:OnLeaveGuild()
    local _guildWin = {
        -- 【G公会系统】删除联盟活跃功能（客户端&服务端）
        -- "WndGuildActiveAwardPop",
        -- "WndGuildActivePop",
        "UIGdApplyForPop",
        "UIGdBraveAwardPop",
        "UIGdBraveLogPop",
        "UIGdBraveWin",
        "UIGdDonatePop",
        "UIGdHeaderPop",
        "UIGdLogPop",
        "UIGdMilPop",
        "UIGdManagePop",
        "UIGdMemberPop",
        "UIGdRecruitPop",
        "UIGdJNPop",
        "UIGdWin",
    }
    for i, v in pairs(_guildWin) do
        if GF.FindFirstWndByName(v) then
            GF.CloseWndByName(v)
        end
    end
    self._guildInfo = nil
    FireEvent(EventNames.CHANGE_MAIN_BTN, LMainBtnIndexConst.CITY)
    gModelChat:DelChannelRed(ModelChat.CHANNEL_GUILD)
    gModelChat:DelChannelCall(ModelChat.CHANNEL_GUILD)
end

function ModelGuild:IsSameGuild(guildId)
    if not self:GetBHaveGuild() then
        return false
    end
    if gModelPlayer:GetGuildId() == tostring(guildId) then
        return true
    end
    return false
end

