function ModelGuild:GetGuildDonatePrice(refId)
    local ref = self:GetGuildDonateRef(refId)
    if not ref or string.isempty(ref.timeLimit) then return end

    local timeLimit = ref.timeLimit
    local num = gModelGuild:GetDonateNumByRefId(refId)
    if timeLimit - num > 0 then
        local priceArr = {}
        local refPrice = string.split(ref.price, "|")
        for i, v in ipairs(refPrice) do
            local price = gModelGeneral:GetParseItem_3(v)
            table.insert(priceArr, price)
        end
        local len = #priceArr
        return num < len and priceArr[num + 1] or priceArr[len]
    end
end
